const modelos = $input.first().json.data;

const modelosDeseados = [
  'openai/text-embedding-3-small',
  'meta-llama/llama-3.1-8b-instruct',
  'google/gemini-2.5-flash'
];

const result = [];

for (const modelo of modelos) {
  if (modelosDeseados.some(m => modelo.id.includes(m.split('/')[1]))) {
    result.push({
      json: {
        modelo: modelo.id,
        precio_input: parseFloat(modelo.pricing.prompt),
        precio_output: parseFloat(modelo.pricing.completion)
      }
    });
  }
}

// Si no encuentra alguno, agregar precios fijos como fallback
const encontrados = result.map(r => r.json.modelo);

if (!encontrados.some(m => m.includes('text-embedding'))) {
  result.push({ json: { modelo: 'openai/text-embedding-3-small', precio_input: 0.00000002, precio_output: 0.00000002 } });
}
if (!encontrados.some(m => m.includes('llama-3.1-8b'))) {
  result.push({ json: { modelo: 'meta-llama/llama-3.1-8b-instruct', precio_input: 0.00000005, precio_output: 0.00000008 } });
}
if (!encontrados.some(m => m.includes('gemini-2.5-flash'))) {
  result.push({ json: { modelo: 'google/gemini-2.5-flash', precio_input: 0.0000003, precio_output: 0.0000025 } });
}

return result;
